import{_ as e,o as a,c as o,a2 as n}from"./chunks/framework.DGp-bpT-.js";const b=JSON.parse('{"title":"Interactive Web Dashboard","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://srebot.site360.tech/docs/en/guide/dashboard.md"}],["link",{"rel":"alternate","hreflang":"ru","href":"https://srebot.site360.tech/docs/guide/dashboard.md"}],["link",{"rel":"alternate","hreflang":"en","href":"https://srebot.site360.tech/docs/en/guide/dashboard.md"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://srebot.site360.tech/docs/guide/dashboard.md"}]]},"headers":[],"relativePath":"en/guide/dashboard.md","filePath":"en/guide/dashboard.md","lastUpdated":1779959939000}'),r={name:"en/guide/dashboard.md"};function i(s,t,d,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="interactive-web-dashboard" tabindex="-1">Interactive Web Dashboard <a class="header-anchor" href="#interactive-web-dashboard" aria-label="Permalink to &quot;Interactive Web Dashboard&quot;">​</a></h1><p>The <a href="https://srebot.site360.tech" target="_blank" rel="noreferrer">SREBot Web Dashboard</a> is your platform&#39;s central control panel. Here you track incidents, manage AI agents, monitor token balances, and configure your account.</p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>The dashboard interface consists of a <strong>sidebar menu</strong> and a <strong>top navigation bar</strong>.</p><h3 id="sidebar-menu" tabindex="-1">Sidebar Menu <a class="header-anchor" href="#sidebar-menu" aria-label="Permalink to &quot;Sidebar Menu&quot;">​</a></h3><p>The sidebar contains links to all dashboard sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Overview</td><td><code>/dashboard</code></td><td>Usage statistics and recent incidents</td></tr><tr><td>Incidents</td><td><code>/dashboard/incidents</code></td><td>Full incident list with filtering</td></tr><tr><td>Bots</td><td><code>/dashboard/bots</code></td><td>AI agent token management</td></tr><tr><td>Billing</td><td><code>/dashboard/billing</code></td><td>Balance, tariffs, transaction history</td></tr><tr><td>Settings</td><td><code>/dashboard/settings</code></td><td>Password and organization profile</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Section visibility depends on role</p><p>The <strong>Billing</strong> and <strong>Team</strong> sections are visible only to users with the <strong>Owner</strong> or <strong>Admin</strong> role. Members and Viewers see only Overview, Incidents, and Settings.</p></div><h3 id="organization-switcher" tabindex="-1">Organization Switcher <a class="header-anchor" href="#organization-switcher" aria-label="Permalink to &quot;Organization Switcher&quot;">​</a></h3><p>The top navigation bar contains an <strong>organization dropdown</strong>. If you belong to multiple organizations, click the current organization name to switch. All dashboard data (incidents, balance, bots) is scoped to the selected organization.</p><hr><h2 id="overview-dashboard" tabindex="-1">Overview (<code>/dashboard</code>) <a class="header-anchor" href="#overview-dashboard" aria-label="Permalink to &quot;Overview (`/dashboard`)&quot;">​</a></h2><p>The main dashboard page provides a quick snapshot of your organization&#39;s activity.</p><h3 id="statistics-cards" tabindex="-1">Statistics Cards <a class="header-anchor" href="#statistics-cards" aria-label="Permalink to &quot;Statistics Cards&quot;">​</a></h3><p>At the top of the page are three cards showing key usage metrics:</p><table tabindex="0"><thead><tr><th>Card</th><th>Description</th></tr></thead><tbody><tr><td><strong>Total Incidents</strong></td><td>Total number of processed incidents of all time</td></tr><tr><td><strong>Prompt Tokens</strong></td><td>Number of input tokens sent to the LLM</td></tr><tr><td><strong>Generation Tokens</strong></td><td>Number of output tokens generated by the LLM</td></tr></tbody></table><p>Each card displays a <strong>weekly trend percentage</strong> — a green arrow for growth and a red arrow for decline — so you can assess consumption dynamics at a glance.</p><h3 id="recent-incidents" tabindex="-1">Recent Incidents <a class="header-anchor" href="#recent-incidents" aria-label="Permalink to &quot;Recent Incidents&quot;">​</a></h3><p>Below the cards is a table of the <strong>5 most recent incidents</strong> with summary information:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Alert</strong></td><td>Name of the alert that triggered the incident</td></tr><tr><td><strong>Bot</strong></td><td>Name of the AI agent that processed the incident</td></tr><tr><td><strong>Status</strong></td><td>Color indicator: 🟢 <code>completed</code>, 🟡 <code>analyzing</code>, 🔴 <code>failed</code></td></tr><tr><td><strong>Time</strong></td><td>Date and time of detection</td></tr><tr><td><strong>Severity</strong></td><td>Severity level: <code>high</code>, <code>medium</code>, <code>low</code></td></tr></tbody></table><p>Click on an incident row to navigate to its detail page.</p><hr><h2 id="bot-management-dashboard-bots" tabindex="-1">Bot Management (<code>/dashboard/bots</code>) <a class="header-anchor" href="#bot-management-dashboard-bots" aria-label="Permalink to &quot;Bot Management (`/dashboard/bots`)&quot;">​</a></h2><p>::: new The <strong>Bots</strong> section is the new home for managing your organization&#39;s AI agent tokens. Here you create, view, and revoke the tokens that bots use to connect to the SREBot platform. :::</p><h3 id="token-list" tabindex="-1">Token List <a class="header-anchor" href="#token-list" aria-label="Permalink to &quot;Token List&quot;">​</a></h3><p>The page displays a table of all agent tokens in the organization:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Bot name specified when creating the token</td></tr><tr><td><strong>Created</strong></td><td>When the token was generated</td></tr><tr><td><strong>Status</strong></td><td><code>Active</code> or <code>Revoked</code></td></tr></tbody></table><h3 id="creating-a-new-token" tabindex="-1">Creating a New Token <a class="header-anchor" href="#creating-a-new-token" aria-label="Permalink to &quot;Creating a New Token&quot;">​</a></h3><ol><li>Click the <strong>&quot;Create Token&quot;</strong> button in the top-right corner.</li><li>In the modal dialog, enter a <strong>bot name</strong> (e.g., <code>prod-bot-1</code>).</li><li>Click <strong>&quot;Create&quot;</strong>.</li><li>The system generates a secret token and displays it in the modal.</li></ol><div class="danger custom-block"><p class="custom-block-title">Token is shown only once</p><p>Immediately after creation, copy the token and store it in a secure location (e.g., a secrets manager). After closing the modal, <strong>the token cannot be viewed again</strong>. If you lose the token, you must revoke it and create a new one.</p></div><p>For convenience, a <strong>copy-to-clipboard</strong> button is placed next to the token.</p><h3 id="revoking-a-token" tabindex="-1">Revoking a Token <a class="header-anchor" href="#revoking-a-token" aria-label="Permalink to &quot;Revoking a Token&quot;">​</a></h3><p>To revoke a token:</p><ol><li>Click the trash icon on the token&#39;s row.</li><li>In the confirmation dialog, click <strong>&quot;Revoke&quot;</strong>.</li></ol><p>Once revoked, the bot immediately loses access to the platform. This action is irreversible — to restore access, create a new token.</p><h3 id="token-limit" tabindex="-1">Token Limit <a class="header-anchor" href="#token-limit" aria-label="Permalink to &quot;Token Limit&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Maximum 10 tokens</p><p>Each organization can have at most <strong>10 active tokens</strong>. Attempting to create an eleventh will show an error. If you need more tokens, revoke unused ones first.</p></div><hr><h2 id="incident-list-dashboard-incidents" tabindex="-1">Incident List (<code>/dashboard/incidents</code>) <a class="header-anchor" href="#incident-list-dashboard-incidents" aria-label="Permalink to &quot;Incident List (`/dashboard/incidents`)&quot;">​</a></h2><p>A paginated list of all organization incidents with search, filtering, and pagination support.</p><h3 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h3><p>Above the table are filter controls:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Full-text search by alert name</td></tr><tr><td><strong>Start Date</strong></td><td>Filter by earliest detection date</td></tr><tr><td><strong>End Date</strong></td><td>Filter by latest detection date</td></tr></tbody></table><h3 id="incident-table" tabindex="-1">Incident Table <a class="header-anchor" href="#incident-table" aria-label="Permalink to &quot;Incident Table&quot;">​</a></h3><p>Incidents are displayed in a paginated table (<strong>20 records per page</strong>) with the following columns:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Alert</strong></td><td>Alert name (e.g., <code>HighCpuUsage</code>)</td></tr><tr><td><strong>Bot</strong></td><td>Name of the agent that processed the incident</td></tr><tr><td><strong>Status</strong></td><td>Color badge: 🟡 <code>analyzing</code>, 🟢 <code>completed</code>, 🔴 <code>failed</code></td></tr><tr><td><strong>Time</strong></td><td>Date and time the incident was detected</td></tr><tr><td><strong>Severity</strong></td><td>Severity level (<code>high</code> / <code>medium</code> / <code>low</code>)</td></tr><tr><td><strong>Actions</strong></td><td>Button to navigate to the incident detail page</td></tr></tbody></table><p>Use the pagination controls at the bottom of the table to navigate between pages.</p><hr><h2 id="incident-detail-dashboard-incidents-id" tabindex="-1">Incident Detail (<code>/dashboard/incidents/:id</code>) <a class="header-anchor" href="#incident-detail-dashboard-incidents-id" aria-label="Permalink to &quot;Incident Detail (`/dashboard/incidents/:id`)&quot;">​</a></h2><p>The incident detail page is the key tool for analyzing the AI agent&#39;s work. It allows you to verify the bot&#39;s reasoning (hallucination check) and reuse its PromQL queries for building new Grafana dashboards.</p><h3 id="root-cause-analysis" tabindex="-1">Root Cause Analysis <a class="header-anchor" href="#root-cause-analysis" aria-label="Permalink to &quot;Root Cause Analysis&quot;">​</a></h3><p>The main block of the page contains the <strong>final LLM output</strong> for the incident, rendered as Markdown. In this block, the bot describes:</p><ul><li>What happened;</li><li>The probable cause of the failure;</li><li>Recommendations for remediation.</li></ul><h3 id="follow-up-questions" tabindex="-1">Follow-up Questions <a class="header-anchor" href="#follow-up-questions" aria-label="Permalink to &quot;Follow-up Questions&quot;">​</a></h3><p>If follow-up questions were asked about the incident via chat, they appear below the analysis block as <strong>&quot;Question → Answer&quot;</strong> pairs. For each follow-up, the following is displayed:</p><ul><li>The user&#39;s question text;</li><li>The bot&#39;s response;</li><li><strong>Token breakdown</strong> — how many input and output tokens were consumed for the specific answer.</li></ul><h3 id="analysis-steps" tabindex="-1">Analysis Steps <a class="header-anchor" href="#analysis-steps" aria-label="Permalink to &quot;Analysis Steps&quot;">​</a></h3><p>A section with collapsible panels showing the <strong>LLM&#39;s thought process</strong> — which tools and queries the bot used during incident analysis.</p><p>Each step contains:</p><table tabindex="0"><thead><tr><th>Element</th><th>Description</th></tr></thead><tbody><tr><td><strong>Phase</strong></td><td>Stage name (e.g., <code>PromQL Query</code>, <code>Elasticsearch Search</code>)</td></tr><tr><td><strong>Query Arguments</strong></td><td>Parameters passed to the tool (e.g., PromQL expression or DSL query)</td></tr><tr><td><strong>Response</strong></td><td>Abbreviated payload returned by the tool</td></tr></tbody></table><p>Click on a step header to expand or collapse the details.</p><div class="tip custom-block"><p class="custom-block-title">Reusing queries</p><p>If the bot executed a successful PromQL query, you can copy it from the analysis steps and use it to build a Grafana dashboard or configure alert rules.</p></div><h3 id="metadata-sidebar" tabindex="-1">Metadata Sidebar <a class="header-anchor" href="#metadata-sidebar" aria-label="Permalink to &quot;Metadata Sidebar&quot;">​</a></h3><p>To the right of the main content is a panel with incident metadata:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Duration</strong></td><td>Time spent on analysis</td></tr><tr><td><strong>Detected</strong></td><td>Date and time the incident was detected</td></tr><tr><td><strong>Input Tokens</strong></td><td>Number of tokens sent to the LLM</td></tr><tr><td><strong>Output Tokens</strong></td><td>Number of tokens generated by the LLM</td></tr><tr><td><strong>Bot</strong></td><td>Name of the agent that processed the incident</td></tr><tr><td><strong>Incident ID</strong></td><td>Unique identifier</td></tr><tr><td><strong>Severity</strong></td><td>Severity level (<code>high</code> / <code>medium</code> / <code>low</code>)</td></tr></tbody></table><hr><h2 id="billing-tokens-dashboard-billing" tabindex="-1">Billing &amp; Tokens (<code>/dashboard/billing</code>) <a class="header-anchor" href="#billing-tokens-dashboard-billing" aria-label="Permalink to &quot;Billing &amp; Tokens (`/dashboard/billing`)&quot;">​</a></h2><p>SREBot uses a <strong>token-based</strong> billing system to charge for LLM invocations. All spending and top-up information is consolidated on this page.</p><h3 id="current-balance" tabindex="-1">Current Balance <a class="header-anchor" href="#current-balance" aria-label="Permalink to &quot;Current Balance&quot;">​</a></h3><p>At the top of the page is your organization&#39;s <strong>current token balance</strong>. Below the balance is a <strong>mini bar chart for the last 14 days</strong>, where:</p><ul><li><strong>Green bars</strong> represent top-ups (credits);</li><li><strong>Red bars</strong> represent usage charges (debits).</li></ul><p>The chart lets you quickly assess spending dynamics.</p><h3 id="current-tariff" tabindex="-1">Current Tariff <a class="header-anchor" href="#current-tariff" aria-label="Permalink to &quot;Current Tariff&quot;">​</a></h3><p>Next to the balance is a card showing the <strong>active tariff plan</strong>:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><strong>Price per 1M tokens</strong></td><td>Cost per one million input tokens</td></tr><tr><td><strong>Output multiplier</strong></td><td>Coefficient applied to the base price for output tokens (output is typically more expensive)</td></tr><tr><td><strong>Currency</strong></td><td>Billing currency — <strong>RUB</strong> or <strong>USD</strong></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Currency selection</p><p>The organization&#39;s currency is determined <strong>at creation time</strong> based on the selected interface language and cannot be changed later.</p></div><h3 id="adding-funds-top-up" tabindex="-1">Adding Funds (Top-up) <a class="header-anchor" href="#adding-funds-top-up" aria-label="Permalink to &quot;Adding Funds (Top-up)&quot;">​</a></h3><ol><li>Click the <strong>&quot;Top Up&quot;</strong> button next to the balance.</li><li>In the modal dialog, enter the <strong>number of tokens</strong> to add. <ul><li>Minimum: <strong>100,000 tokens</strong></li><li>Maximum: <strong>100,000,000 tokens</strong></li></ul></li><li>The system automatically calculates the <strong>estimated cost</strong> in your organization&#39;s currency.</li><li>Click <strong>&quot;Pay&quot;</strong> — you will be redirected to the payment gateway.</li></ol><p>After successful payment, the balance updates automatically.</p><h3 id="transaction-history" tabindex="-1">Transaction History <a class="header-anchor" href="#transaction-history" aria-label="Permalink to &quot;Transaction History&quot;">​</a></h3><p>At the bottom of the page is a table of all balance operations with filtering support:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td><strong>Transaction Type</strong></td><td>Filter by category (see below)</td></tr><tr><td><strong>Date Range</strong></td><td>Filter by transaction date</td></tr></tbody></table><h4 id="transaction-types" tabindex="-1">Transaction Types <a class="header-anchor" href="#transaction-types" aria-label="Permalink to &quot;Transaction Types&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Usage</strong></td><td>Charge for incident analysis or follow-up question</td></tr><tr><td><strong>Top-up</strong></td><td>Balance top-up via payment gateway</td></tr><tr><td><strong>Gift</strong></td><td>Gift tokens credited by an administrator</td></tr><tr><td><strong>Refund</strong></td><td>Refund (e.g., for an erroneous charge)</td></tr></tbody></table><p><strong>Usage</strong> transactions contain a link to the associated incident — click it to navigate to the incident detail page and see exactly what the tokens were charged for.</p><h3 id="negative-balance-protection" tabindex="-1">Negative Balance Protection <a class="header-anchor" href="#negative-balance-protection" aria-label="Permalink to &quot;Negative Balance Protection&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Analysis blocked</p><p>If your balance drops <strong>below zero</strong>, SREBot <strong>stops analyzing new alerts</strong>. Instead, a notification is sent to the chat (Telegram/Slack/Discord) indicating the need to top up. Analysis resumes automatically after the balance is replenished.</p></div><hr><h2 id="account-settings-dashboard-settings" tabindex="-1">Account &amp; Settings (<code>/dashboard/settings</code>) <a class="header-anchor" href="#account-settings-dashboard-settings" aria-label="Permalink to &quot;Account &amp; Settings (`/dashboard/settings`)&quot;">​</a></h2><p>The settings page lets you manage your profile parameters and organization context.</p><h3 id="changing-password" tabindex="-1">Changing Password <a class="header-anchor" href="#changing-password" aria-label="Permalink to &quot;Changing Password&quot;">​</a></h3><p>To change your password:</p><ol><li>Enter your current password in the <strong>&quot;Current Password&quot;</strong> field.</li><li>Enter a new password in the <strong>&quot;New Password&quot;</strong> field (minimum 8 characters).</li><li>Confirm the new password in the <strong>&quot;Confirm Password&quot;</strong> field.</li><li>Click <strong>&quot;Save&quot;</strong>.</li></ol><h3 id="organization-context" tabindex="-1">Organization Context <a class="header-anchor" href="#organization-context" aria-label="Permalink to &quot;Organization Context&quot;">​</a></h3><p>The settings page displays information about the current organization:</p><ul><li><strong>Organization Name</strong></li><li><strong>Your Role</strong> in this organization (Owner / Admin / Member / Viewer)</li></ul><p>To manage organization members, navigate to the <strong>&quot;Team&quot;</strong> section (available only to Owners and Admins). For more details, see <a href="/docs/en/guide/team-management">Team Management</a>.</p>',97)])])}const u=e(r,[["render",i]]);export{b as __pageData,u as default};
